<?php namespace App\Contracts; use Illuminate\Http\JsonResponse; interface ApiResponseContract { /** * إرجاع استجابة نجاح (Success) مع البيانات الاختيارية. * * @param mixed $data * @param string|null $message * @param int $code * @return JsonResponse */ public function success($data = null, ?string $message = null, int $code = 200): JsonResponse; /** * إرجاع استجابة خطأ عام (Error) مع تفاصيل اختيارية. * * @param string $message * @param int $code * @param array $errors * @return JsonResponse */ public function error(string $message, int $code = 400, array $errors = []): JsonResponse; /** * إرجاع استجابة أخطاء التحقق من صحة البيانات (Validation Errors). * * @param array $errors * @param string $message * @return JsonResponse */ public function validationError(array $errors, string $message = 'حدث خطأ في التحقق من صحة البيانات'): JsonResponse; }